class Solution {
    public List<List<Integer>> largeGroupPositions(String s) {
        List<List<Integer>> result = new ArrayList<>();
        int start = 0, end = 0;
        while (end < s.length()) {
            if (end + 1 < s.length() && s.charAt(end) == s.charAt(end + 1)) {
                end++;
            } else {
                if (end - start + 1 >= 3) {
                    result.add(Arrays.asList(start, end));
                }
                end++;
                start = end;
            }
        }
        return result;
    }
}
